        data: IPCountryData(
            id: "103.108.116.3",
            type: "GeoIpInfo",
            attributes: IPCountryAttributes(
                ip: "103.108.116.3",
                country: "RU",
                isGdprConsentRequired: false)))

    func makeSut(
        bootStrapServiceResponse: IPCountryResponse?,
        mockedDefaultCountry: Country = MockCountryManager.Russia,
        savedCountryParam: String? = nil
    ) async -> DetectionResult {
        let useCase = DetectCountryUseCaseImpl(
            MockBootstrapService().amend {
                $0.stubbedIPCountryResponse = bootStrapServiceResponse
            },
            MockCountryManager(defaultCountry: mockedDefaultCountry))

        return await useCase(savedCountryParam)
    }

    @Test("Chooses default country if there is no other information")
    func defaultIfNoOthers() async {
        let result = await makeSut(
            bootStrapServiceResponse: nil,
            mockedDefaultCountry: MockCountryManager.China,
            savedCountryParam: nil)

        #expect(result.resultType == .usedDefault)
        #expect(result.country.code == "CN")
    }

    @Test("Returns detected country if nothing saved was provided")
    func detectedOverDefault() async {
        let result = await makeSut(
            bootStrapServiceResponse: ruResponse,
            mockedDefaultCountry: MockCountryManager.China,
            savedCountryParam: nil)

        #expect(result.resultType == .detected)
        #expect(result.country.code == "RU")
