        let result = await makeSut(
            bootStrapServiceResponse: ruResponse,
            mockedDefaultCountry: MockCountryManager.China,
            savedCountryParam: "IN")

        #expect(result.resultType == .saved)
        #expect(result.country.code == "IN")
